#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""Raise PG max_connections 100->200 with AUTO-ROLLBACK (exit-0-safe). Removes the
connection ceiling that async-ramp/enrich-pool/growth-engines contend over. Uses
ALTER SYSTEM (reversible) + restart; if PG doesn't come back healthy at 200, RESET +
restart and report rolled_back. Then restarts the email-scaler + ICP ranker units."""
import os,sys,json,time,subprocess,base64,urllib.request,urllib.error
def run(args,t=60):
    try:
        r=subprocess.run(args,capture_output=True,text=True,timeout=t); return r.returncode,(r.stdout+r.stderr).strip()
    except Exception as e: return 99,"ERR:%s"%e
def psql(q,t=30):
    for pre in (["sudo","-u","postgres","psql","-tAc",q],
                ["su","-s","/bin/sh","postgres","-c","psql -tAc \"%s\""%q.replace('"','\\"')]):
        rc,o=run(pre,t)
        if rc==0: return o
    return "ERR"
def sh(c,t=60): return run(["bash","-lc",c],t)
def pg_unit():
    rc,o=sh("systemctl list-units --plain --no-legend 'postgresql*' 2>/dev/null | awk '{print $1}' | grep -E 'postgresql@.*-main\\.service|^postgresql\\.service' | head -1")
    return o.strip() or "postgresql.service"
out={"kind":"maxconn","ts":int(time.time())}
try:
    unit=pg_unit(); out["pg_unit"]=unit
    out["before_max"]=psql("SHOW max_connections")
    out["before_total"]=psql("SELECT count(*) FROM pg_stat_activity")
    # raise
    out["alter"]=psql("ALTER SYSTEM SET max_connections=200")
    rc,o=sh("systemctl restart %s"%unit, t=90); out["restart_rc"]=rc
    # wait for healthy
    healthy=False
    for _ in range(20):
        time.sleep(3)
        rc,o=sh("pg_isready 2>&1"); 
        if rc==0: healthy=True; break
    out["pg_isready_ok"]=healthy
    newmax=psql("SHOW max_connections") if healthy else "n/a"
    out["after_max"]=newmax
    if not (healthy and str(newmax).strip()=="200"):
        # ROLLBACK
        psql("ALTER SYSTEM RESET max_connections")
        sh("systemctl restart %s"%unit, t=90)
        time.sleep(6)
        out["rolled_back"]=True
        out["after_rollback_isready"]=sh("pg_isready 2>&1")[1]
        out["after_rollback_max"]=psql("SHOW max_connections")
    else:
        out["rolled_back"]=False
        out["new_total"]=psql("SELECT count(*) FROM pg_stat_activity")
        # kick growth engines now that there's headroom
        kicked=[]
        rc,svcs=sh("systemctl list-unit-files --no-legend 2>/dev/null | grep -iE '(deepcrawl|icp|email|scaler|rank)' | grep -E '\\.service' | grep -vE 'enrich-pool' | awk '{print $1}' | head -10")
        for u in svcs.split():
            if u.endswith('.service'):
                r2=sh("systemctl restart %s 2>&1; echo rc=$?"%u,t=40); kicked.append(u+":"+r2[1][-12:])
        out["kicked"]=kicked
except Exception as e:
    out["error"]=str(e)
def envf(p):
    d={}
    try:
        for ln in open(p):
            ln=ln.strip()
            if ln.startswith('export '): ln=ln[7:]
            if '=' in ln and not ln.startswith('#'):
                k,v=ln.split('=',1); d[k.strip()]=v.strip().strip('"').strip("'")
    except Exception: pass
    return d
try:
    env=envf("/etc/atlas/autopull.env")
    tok=env.get("STATUS_TOKEN") or os.environ.get("STATUS_TOKEN"); repo=env.get("STATUS_REPO") or "cloudwalker171/atlas-manifests"
    br=env.get("STATUS_BRANCH","main"); api="https://api.github.com"; path="status/hetzner/maxconn.json"
    if tok and repo:
        url="%s/repos/%s/contents/%s"%(api,repo,path); sha=None
        try:
            r=urllib.request.Request(url+"?ref="+br,headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); sha=json.load(urllib.request.urlopen(r,timeout=20)).get("sha")
        except Exception: sha=None
        body={"message":"maxconn","content":base64.b64encode(json.dumps(out,indent=2,default=str).encode()).decode(),"branch":br}
        if sha: body["sha"]=sha
        for _ in range(4):
            try:
                rq=urllib.request.Request(url,data=json.dumps(body).encode(),method="PUT",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas","Content-Type":"application/json"}); urllib.request.urlopen(rq,timeout=25); break
            except urllib.error.HTTPError as e:
                if e.code==409:
                    try:
                        rq2=urllib.request.Request(url+"?ref="+br,headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); body["sha"]=json.load(urllib.request.urlopen(rq2,timeout=20)).get("sha")
                    except Exception: pass
                else: break
            except Exception: time.sleep(2)
except Exception: pass
sys.exit(0)
